import zeep
from zeep import Client
from zeep.transports import Transport
from requests import Session
from requests.auth import HTTPBasicAuth
import sys

def create_secure_client(wsdl_url, username, password):
    session = Session()
    session.auth = HTTPBasicAuth(username, password)
    
    transport = Transport(session=session, timeout=30)
    client = Client(wsdl_url, transport=transport)
    return client

def lookup_policy(client, policy_number, customer_name):
    try:
        # Create SOAP request with user input
        request_data = {
            'policyNumber': policy_number,
            'customerName': customer_name
        }
        
        # Call the SOAP service
        response = client.service.LookupPolicy(**request_data)
        return response
    except Exception as e:
        print(f"Error occurred: {str(e)}")
        return None

def main():
    # Configuration - replace with actual values
    WSDL_URL = "https://example.com/insurance?wsdl"
    USERNAME = "your_username"
    PASSWORD = "your_password"
    
    # Create secure client
    client = create_secure_client(WSDL_URL, USERNAME, PASSWORD)
    
    # Get user input
    try:
        policy_number = input("Enter policy number: ").strip()
        customer_name = input("Enter customer name: ").strip()
        
        # Validate input
        if not policy_number or not customer_name:
            print("Error: Policy number and customer name are required.")
            sys.exit(1)
        
        # Perform lookup
        result = lookup_policy(client, policy_number, customer_name)
        
        if result:
            print("Policy lookup successful:")
            print(result)
        else:
            print("Policy lookup failed.")
            
    except KeyboardInterrupt:
        print("\nOperation cancelled by user.")
        sys.exit(0)
    except Exception as e:
        print(f"Unexpected error: {str(e)}")
        sys.exit(1)

if __name__ == "__main__":
    main()